const incident = $input.first().json;
const title = incident.incident.title.toLowerCase();

// Map incident title patterns to IR playbook types
const classify = (t) => {
  if (t.includes('breach') || t.includes('exfil') || t.includes('pan')) return 'data-breach';
  if (t.includes('ransomware') || t.includes('encrypt')) return 'ransomware';
  if (t.includes('ddos') || t.includes('spike') || t.includes('flood')) return 'ddos';
  if (t.includes('privilege') || t.includes('escalat') || t.includes('sudo')) return 'privilege-escalation';
  if (t.includes('malware') || t.includes('trojan') || t.includes('backdoor')) return 'malware';
  if (t.includes('compromise') || t.includes('account') || t.includes('credential')) return 'account-compromise';
  return 'generic-security-incident';
};

const incidentType = classify(title);

// Playbook defines containment steps and evidence to collect
const playbooks = {
  'data-breach': {
    containment: ['isolate_host', 'revoke_credentials', 'block_exfil_ips'],
    evidence: ['memory_dump', 'disk_image', 'network_logs', 'vault_audit_log'],
    severity: 'SEV1',
    compliance: ['PCI DSS 12.10.2', 'GDPR Art. 33']
  },
  'ransomware': {
    containment: ['isolate_host', 'disable_backups_write', 'snapshot_volumes'],
    evidence: ['disk_image', 'process_list', 'network_connections'],
    severity: 'SEV1',
    compliance: ['NIST SP 800-61']
  },
  'privilege-escalation': {
    containment: ['lock_account', 'revoke_sudo', 'kill_processes'],
    evidence: ['auth_logs', 'process_list', 'bash_history'],
    severity: 'SEV2',
    compliance: ['PCI DSS 10.2.1.3']
  },
  'account-compromise': {
    containment: ['force_logout', 'revoke_tokens', 'mfa_reset'],
    evidence: ['login_history', 'api_access_logs', 'oauth_tokens'],
    severity: 'SEV2',
    compliance: ['PCI DSS 8.2.1']
  }
};

const playbook = playbooks[incidentType] || playbooks['generic-security-incident'] || {
  containment: ['isolate_host'],
  evidence: ['network_logs', 'auth_logs'],
  severity: 'SEV2',
  compliance: []
};

return [{
  json: {
    incidentId: incident.incident.id,
    incidentUrl: incident.incident.html_url,
    title: incident.incident.title,
    incidentType,
    severity: playbook.severity,
    containmentSteps: playbook.containment,
    evidenceToCollect: playbook.evidence,
    complianceRequirements: playbook.compliance,
    timestamp: new Date().toISOString(),
    responder: incident.incident.assignments?.[0]?.assignee?.name || 'Unassigned'
  }
}];

